@page "/dashboard"
@rendermode InteractiveServer
@using sv_fa42dd0c6c8b472ab1b7f4a694a62c99.Services
@inject InventoryAlertService InventoryAlerts
@inject AlertNotificationService AlertNotification
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">Current Warehouse</h5>
        <p class="card-text fs-5">
            @if (Warehouse is not null)
            {
                <strong>@Warehouse.Name</strong> <span class="text-muted">(@Warehouse.Id)</span>
            }
            else
            {
                <em>No warehouse selected</em>
            }
        </p>
    </div>
</div>

<div class="card mb-4" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text">
            @if (_alertCount.HasValue)
            {
                <span class="fs-3 fw-bold @(_alertCount > 0 ? "text-danger" : "text-success")">
                    @_alertCount
                </span>
                <span class="text-muted ms-2">items below minimum level</span>
            }
            else
            {
                <em>Loading…</em>
            }
        </p>
        <small class="text-muted">Refreshes every 10 seconds</small>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private int? _alertCount;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed — refresh immediately and restart the polling loop.
        await StopPollingAsync();
        _alertCount = null;
        await PollOnceAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            try
            {
                while (await _timer.WaitForNextTickAsync(token))
                {
                    await InvokeAsync(async () =>
                    {
                        await PollOnceAsync();
                        StateHasChanged();
                    });
                }
            }
            catch (OperationCanceledException) { }
        });
    }

    private async Task PollOnceAsync()
    {
        if (Warehouse is null) return;
        _alertCount = await InventoryAlerts.GetLowStockCountAsync(Warehouse.Id);
        // Push the count into the shared notification service so all subscribers update.
        AlertNotification.UpdateCount(_alertCount.Value);
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

